import{_ as t,o as a,c as o,ag as s}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"npm 依赖版本号中 ^ 和 ~ 到底有什么区别？","description":"通过真实案例理解 npm 中 ^ 和 ~ 的版本匹配范围与风险。","frontmatter":{"title":"npm 依赖版本号中 ^ 和 ~ 到底有什么区别？","date":"2026-04-09T00:00:00.000Z","tags":["npm","工程化","依赖管理"],"category":"工程化","description":"通过真实案例理解 npm 中 ^ 和 ~ 的版本匹配范围与风险。"},"headers":[],"relativePath":"frontend/engineering/npm-caret-vs-tilde.md","filePath":"frontend/engineering/npm-caret-vs-tilde.md"}'),d={name:"frontend/engineering/npm-caret-vs-tilde.md"};function n(c,e,i,p,l,r){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="npm-依赖版本号中-和-到底有什么区别" tabindex="-1">npm 依赖版本号中 ^ 和 ~ 到底有什么区别？ <a class="header-anchor" href="#npm-依赖版本号中-和-到底有什么区别" aria-label="Permalink to &quot;npm 依赖版本号中 ^ 和 ~ 到底有什么区别？&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>Axios被爆存在投毒风险，需要尽快规避使用0.30.4和1.14.1版本，这正好是一个活生生的例子，帮助大家理解 <code>^</code> 和 <code>~</code> 在实际项目中的影响，在查看 <code>package.json</code> 时，都会看到依赖版本号前面带着 <code>^</code> 或 <code>~</code> 符号，比如：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;dependencies&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;axios&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;^0.21.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;lodash&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;~4.17.20&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;vue&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;^3.2.0&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>你有没有想过：<strong>这两个符号到底代表什么？它们的区别是什么？</strong></p><p>今天我们就来彻底搞清楚这个问题。</p><h2 id="一、先了解语义化版本" tabindex="-1">一、先了解语义化版本 <a class="header-anchor" href="#一、先了解语义化版本" aria-label="Permalink to &quot;一、先了解语义化版本&quot;">​</a></h2><p>在讲 <code>^</code> 和 <code>~</code> 之前，我们必须先理解 npm 采用的<strong>语义化版本规范</strong>。</p><p>一个标准的版本号格式是：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Major.Minor.Patch</span></span>
<span class="line"><span>主版本.次版本.补丁版本</span></span></code></pre></div><p>以 <code>1.2.3</code> 为例：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th><th>什么时候变</th></tr></thead><tbody><tr><td><code>1</code>（Major）</td><td>主版本号</td><td>有<strong>破坏性变更</strong>时递增</td></tr><tr><td><code>2</code>（Minor）</td><td>次版本号</td><td>新增<strong>向下兼容的功能</strong>时递增</td></tr><tr><td><code>3</code>（Patch）</td><td>补丁版本号</td><td>修复<strong>向下兼容的 Bug</strong>时递增</td></tr></tbody></table><p>理解了这个，下面就好说了。</p><h2 id="二、-插入符-—-锁定主版本号" tabindex="-1">二、<code>^</code>（插入符）— 锁定主版本号 <a class="header-anchor" href="#二、-插入符-—-锁定主版本号" aria-label="Permalink to &quot;二、\`^\`（插入符）— 锁定主版本号&quot;">​</a></h2><p><code>^</code> 是 npm 的<strong>默认行为</strong>。当你执行 <code>npm install axios</code> 时，写入 <code>package.json</code> 的就是 <code>^</code> 前缀。</p><p><strong>规则：主版本号不变，允许次版本和补丁版本升级。</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>^1.2.3  →  &gt;=1.2.3  且  &lt;2.0.0</span></span></code></pre></div><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>写法</th><th>允许安装的范围</th><th>能装</th><th>不能装</th></tr></thead><tbody><tr><td><code>^1.2.3</code></td><td><code>1.2.3</code> ~ <code>1.x.x</code></td><td><code>1.2.4</code>、<code>1.9.0</code></td><td><code>2.0.0</code></td></tr><tr><td><code>^2.0.0</code></td><td><code>2.0.0</code> ~ <code>2.x.x</code></td><td><code>2.1.0</code>、<code>2.99.99</code></td><td><code>3.0.0</code></td></tr></tbody></table><h3 id="⚠️-特殊情况-主版本为-0" tabindex="-1">⚠️ 特殊情况：主版本为 0 <a class="header-anchor" href="#⚠️-特殊情况-主版本为-0" aria-label="Permalink to &quot;⚠️ 特殊情况：主版本为 0&quot;">​</a></h3><p>当主版本号是 <code>0</code> 时，<code>^</code> 的行为会<strong>变得更保守</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>^0.21.0  →  &gt;=0.21.0  且  &lt;0.22.0   （只允许补丁更新）</span></span>
<span class="line"><span>^0.0.3   →  &gt;=0.0.3   且  &lt;0.0.4    （完全锁死）</span></span></code></pre></div><p>因为在 semver 规范中，<code>0.x.x</code> 代表<strong>不稳定版本</strong>，任何次版本的变化都可能是破坏性的，所以 npm 在这里做了特殊处理。</p><h2 id="三、-波浪符-—-锁定主版本-次版本号" tabindex="-1">三、<code>~</code>（波浪符）— 锁定主版本 + 次版本号 <a class="header-anchor" href="#三、-波浪符-—-锁定主版本-次版本号" aria-label="Permalink to &quot;三、\`~\`（波浪符）— 锁定主版本 + 次版本号&quot;">​</a></h2><p><strong>规则：主版本号和次版本号都不变，只允许补丁版本升级。</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~1.2.3  →  &gt;=1.2.3  且  &lt;1.3.0</span></span></code></pre></div><h3 id="示例-1" tabindex="-1">示例 <a class="header-anchor" href="#示例-1" aria-label="Permalink to &quot;示例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>写法</th><th>允许安装的范围</th><th>能装</th><th>不能装</th></tr></thead><tbody><tr><td><code>~1.2.3</code></td><td><code>1.2.3</code> ~ <code>1.2.x</code></td><td><code>1.2.4</code>、<code>1.2.99</code></td><td><code>1.3.0</code></td></tr><tr><td><code>~4.17.20</code></td><td><code>4.17.20</code> ~ <code>4.17.x</code></td><td><code>4.17.21</code></td><td><code>4.18.0</code></td></tr></tbody></table><p><code>~</code> 比 <code>^</code> <strong>更保守</strong>，它只接受 bug 修复级别的更新。</p><h2 id="四、一图对比" tabindex="-1">四、一图对比 <a class="header-anchor" href="#四、一图对比" aria-label="Permalink to &quot;四、一图对比&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>版本号：Major.Minor.Patch</span></span>
<span class="line"><span></span></span>
<span class="line"><span>^1.2.3                          ~1.2.3</span></span>
<span class="line"><span>  │                               │</span></span>
<span class="line"><span>  ├── 锁定 Major                  ├── 锁定 Major + Minor</span></span>
<span class="line"><span>  ├── Minor 可升级 ✅              ├── Minor 不可升级 ❌</span></span>
<span class="line"><span>  └── Patch 可升级 ✅              └── Patch 可升级 ✅</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>  范围：1.2.3 ~ 1.x.x             范围：1.2.3 ~ 1.2.x</span></span>
<span class="line"><span>  更宽松，更新更多                   更保守，只收 bug 修复</span></span></code></pre></div><h2 id="五、实际场景理解" tabindex="-1">五、实际场景理解 <a class="header-anchor" href="#五、实际场景理解" aria-label="Permalink to &quot;五、实际场景理解&quot;">​</a></h2><p>假设你的 <code>package.json</code> 中有这么一行：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;axios&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;^1.2.3&quot;</span></span></code></pre></div><p>当你（或你的同事、CI/CD）执行 <code>npm install</code> 时，npm 会在 <code>^1.2.3</code> 的范围内选择<strong>当前可用的最新版本</strong>来安装。</p><ul><li>如果此时 axios 最新版是 <code>1.6.0</code>，就会装 <code>1.6.0</code></li><li>如果此时 axios 最新版是 <code>2.0.0</code>，仍然只会装 <code>1.x.x</code> 的最新版</li></ul><p>如果改为：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;axios&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;~1.2.3&quot;</span></span></code></pre></div><ul><li>如果此时 axios 最新版是 <code>1.2.8</code>，就会装 <code>1.2.8</code></li><li>如果此时 axios 最新版是 <code>1.3.0</code>，仍然只会装 <code>1.2.x</code> 的最新版</li></ul><h2 id="六、其他常见写法" tabindex="-1">六、其他常见写法 <a class="header-anchor" href="#六、其他常见写法" aria-label="Permalink to &quot;六、其他常见写法&quot;">​</a></h2><p>除了 <code>^</code> 和 <code>~</code>，你可能还会见到这些：</p><table tabindex="0"><thead><tr><th>写法</th><th>含义</th></tr></thead><tbody><tr><td><code>1.2.3</code></td><td><strong>精确版本</strong>，只装这个版本</td></tr><tr><td><code>*</code></td><td>任意版本（危险，不建议）</td></tr><tr><td><code>&gt;=1.2.3</code></td><td>大于等于 1.2.3 的任意版本</td></tr><tr><td><code>1.2.x</code></td><td>等同于 <code>~1.2.0</code></td></tr><tr><td><code>1.x</code></td><td>等同于 <code>^1.0.0</code></td></tr></tbody></table><h2 id="七、那到底该用哪个" tabindex="-1">七、那到底该用哪个？ <a class="header-anchor" href="#七、那到底该用哪个" aria-label="Permalink to &quot;七、那到底该用哪个？&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>建议</th></tr></thead><tbody><tr><td>大多数项目</td><td>使用 <code>^</code>（npm 默认），信任社区遵守 semver</td></tr><tr><td>对稳定性要求极高</td><td>使用 <code>~</code>，只接受补丁更新</td></tr><tr><td>线上环境要绝对可控</td><td>使用精确版本，或依赖 <code>package-lock.json</code> 锁版本</td></tr></tbody></table><blockquote><p><strong>最佳实践</strong>：无论用 <code>^</code> 还是 <code>~</code>，都要把 <code>package-lock.json</code> 提交到 Git 仓库。它会精确锁定每个依赖的实际安装版本，确保团队所有人和 CI/CD 环境安装的版本完全一致。</p></blockquote><h2 id="八、实战案例-axios-的版本策略建议" tabindex="-1">八、实战案例：Axios 的版本策略建议 <a class="header-anchor" href="#八、实战案例-axios-的版本策略建议" aria-label="Permalink to &quot;八、实战案例：Axios 的版本策略建议&quot;">​</a></h2><p><strong>情况一：项目使用 <code>0.*.*</code> 版本的 Axios</strong></p><p>如果你的 <code>package.json</code> 中写的是 <code>&quot;axios&quot;: &quot;^0.21.0&quot;</code>，根据前面讲的规则，<code>^0.21.0</code> 的实际范围是 <code>&gt;=0.21.0 且 &lt;0.22.0</code>，行为和 <code>~</code> 一致，最多只会更新到 <code>0.21.x</code>。只要你用的不是 <code>0.30.4</code> 这类已知有问题的版本，基本可以放心，不需要额外修改。</p><p><strong>情况二：项目使用 <code>1.*.*</code> 版本的 Axios</strong></p><p>如果你的 <code>package.json</code> 中写的是 <code>&quot;axios&quot;: &quot;^1.2.0&quot;</code>，那范围就是 <code>&gt;=1.2.0 且 &lt;2.0.0</code>。这意味着：<strong>一旦有团队成员删除了 <code>package-lock.json</code> 后重新 <code>npm install</code>，就有可能安装到 <code>1.14.1</code> 等存在问题的版本。</strong></p><blockquote><p><strong>建议</strong>：对于 <code>1.*.*</code> 版本的 Axios，将版本前缀从 <code>^</code> 改为 <code>~</code>，例如将 <code>&quot;axios&quot;: &quot;^1.2.0&quot;</code> 改为 <code>&quot;axios&quot;: &quot;~1.2.0&quot;</code>，这样即使丢失了 lock 文件，也只会在 <code>1.2.x</code> 范围内更新，大大降低风险。</p></blockquote><p>这个案例也再次说明了一点：<strong><code>package-lock.json</code> 一定要提交到仓库，同时对关键依赖使用 <code>~</code> 可以提供额外的安全网。</strong></p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><ul><li><strong><code>^</code></strong>：宽松策略，锁主版本号，允许 Minor 和 Patch 更新</li><li><strong><code>~</code></strong>：保守策略，锁主版本 + 次版本号，只允许 Patch 更新</li><li>主版本为 <code>0</code> 时，<code>^</code> 会自动变保守，和 <code>~</code> 行为接近</li><li>实际项目中 <code>package-lock.json</code> 才是真正的版本锁，<code>^</code> 和 <code>~</code> 只在 <code>npm install</code> 没有 lock 文件时起作用</li></ul>`,54)])])}const k=t(d,[["render",n]]);export{g as __pageData,k as default};
